def graphTraversal = g.V().hasLabel('movie')
def intermediateResults = []
graphTraversal.toList().each { movieVertex ->
    def movieTraversal = g.V(movieVertex.id())
    def preferredPath = movieTraversal.out('rate').has('title', 'The Matrix')
    def fallbackPathOne = movieTraversal.out('acted_in')
    def fallbackPathTwo = movieTraversal.out('acted_in')
    def selected = null
    if (preferredPath.hasNext()) {
        selected = preferredPath.toList()
    } else if (fallbackPathOne.hasNext()) {
        selected = fallbackPathOne.toList()
    } else {
        selected = fallbackPathTwo.toList()
    }
    selected.each { item ->
        intermediateResults << [
            sourceId: movieVertex.id(),
            sourceLabel: movieVertex.label(),
            value: item,
            valueId: item instanceof org.apache.tinkerpop.gremlin.structure.Element ? item.id() : null
        ]
    }
}
def sortedResults = intermediateResults.sort { a, b ->
    String.valueOf(a.value) <=> String.valueOf(b.value)
}
return [results: sortedResults, count: sortedResults.size()]

