def genreVertices = g.V().hasLabel('genre').toList();
def collectedPeople = [];

genreVertices.each { genre ->
    def actedTraversal = g.V(genre.id()).in('acted_in');
    while (actedTraversal.hasNext()) {
        def actor = actedTraversal.next();
        collectedPeople << [id: actor.id(), label: actor.label(), vertex: actor, sourceGenreId: genre.id(), relation: 'acted_in'];
    }

    def directedTraversal = g.V(genre.id()).in('directed');
    while (directedTraversal.hasNext()) {
        def director = directedTraversal.next();
        collectedPeople << [id: director.id(), label: director.label(), vertex: director, sourceGenreId: genre.id(), relation: 'directed'];
    }
}

def deduped = [:];
collectedPeople.each { personRecord ->
    if (!deduped.containsKey(personRecord.id)) {
        deduped[personRecord.id] = [person: personRecord.vertex, meta: [label: personRecord.label, discoveredFrom: personRecord.sourceGenreId, via: personRecord.relation]];
    }
}

return deduped.values().collect { it.person }

